#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_home_path_redaction() {
        let config = RedactionConfig {
            redact_home_paths: true,
            ..Default::default()
        };
        let engine = RedactionEngine::new(config);

        // Mock home directory
        let input = "/home/testuser/projects/myapp/src/main.rs";
        let result = engine.redact(input);

        assert!(result.output.contains("~/projects"));
        assert!(!result.output.contains("testuser"));
    }

    #[test]
    fn test_username_redaction() {
        let mut config = RedactionConfig::default();
        config.redact_usernames = true;

        let engine = RedactionEngine::new(config);
        let input = "Error in /Users/johnsmith/code/app.rs";
        let result = engine.redact(input);

        assert!(result.output.contains("/Users/user/"));
        assert!(!result.output.contains("johnsmith"));
    }

    #[test]
    fn test_custom_patterns() {
        let mut config = RedactionConfig::default();
        config.custom_patterns.push(CustomPattern {
            name: "Project codename".into(),
            pattern: Regex::new(r"Project\s+Falcon").unwrap(),
            replacement: "Project X".into(),
            enabled: true,
        });

        let engine = RedactionEngine::new(config);
        let input = "Working on Project Falcon deployment";
        let result = engine.redact(input);

        assert_eq!(result.output, "Working on Project X deployment");
    }

    #[test]
    fn test_redaction_report() {
        let config = RedactionConfig {
            redact_home_paths: true,
            redact_usernames: true,
            ..Default::default()
        };
        let engine = RedactionEngine::new(config);

        let hits = vec![create_test_hit_with_paths()];
        let report = engine.generate_report(&hits);

        assert!(report.total_redactions > 0);
        assert!(report.by_kind.contains_key(&RedactionKind::HomePath));
    }
}
