// Attachments are NOT prefetched - loaded on demand only
async function loadAttachment(hash, dek) {
    const response = await fetch(`./blobs/${hash}.bin`);
    if (!response.ok) {
        throw new Error(`Attachment ${hash} not found`);
    }

    const encrypted = new Uint8Array(await response.arrayBuffer());

    // Extract nonce (first 12 bytes)
    const nonce = encrypted.slice(0, 12);
    const ciphertext = encrypted.slice(12);

    // Build AAD
    const aad = buildBlobAad(exportId, hash);

    // Decrypt
    const dekKey = await crypto.subtle.importKey(
        'raw', dek, { name: 'AES-GCM' }, false, ['decrypt']
    );

    const plaintext = await crypto.subtle.decrypt(
        { name: 'AES-GCM', iv: nonce, additionalData: aad },
        dekKey,
        ciphertext
    );

    return new Uint8Array(plaintext);
}
```

### Preview Rendering
```javascript
async function renderAttachment(hash, mimeType, container) {
    const data = await loadAttachment(hash, sessionDek);
    const blob = new Blob([data], { type: mimeType });
    const url = URL.createObjectURL(blob);

    try {
        if (mimeType.startsWith('image/')) {
            const img = document.createElement('img');
            img.src = url;
            img.className = 'attachment-image';
            container.appendChild(img);
        } else if (mimeType === 'application/pdf') {
            const embed = document.createElement('embed');
            embed.src = url;
            embed.type = 'application/pdf';
            embed.className = 'attachment-pdf';
            container.appendChild(embed);
        } else if (mimeType.startsWith('text/')) {
            const pre = document.createElement('pre');
            pre.textContent = new TextDecoder().decode(data);
            pre.className = 'attachment-text';
            Prism.highlightElement(pre);
            container.appendChild(pre);
        } else {
            // Download button for other types
            const link = document.createElement('a');
            link.href = url;
            link.download = getFilename(hash);
            link.textContent = 'Download attachment';
            link.className = 'attachment-download';
            container.appendChild(link);
        }
    } finally {
        // Revoke after a delay to allow rendering
        setTimeout(() => URL.revokeObjectURL(url), 5000);
    }
}
```

### Message Rendering Integration
```javascript
function renderMessage(message) {
    let content = DOMPurify.sanitize(marked.parse(message.content));

    // Replace attachment references with lazy-load placeholders
    if (message.attachment_refs) {
        const refs = JSON.parse(message.attachment_refs);
        for (const hash of refs) {
            const attachment = attachmentIndex.get(hash);
            if (attachment) {
                content = content.replace(
                    new RegExp(escapeRegex(attachment.original_ref), 'g'),
                    `<div class="attachment-placeholder" data-hash="${hash}" data-mime="${attachment.mime_type}">
                        <button onclick="loadAndRenderAttachment('${hash}', this.parentNode)">
                            📎 ${attachment.filename} (${formatBytes(attachment.size_bytes)})
                        </button>
                    </div>`
                );
            }
        }
    }

    return content;
}
